// Minimal SweetAlert2-ish shim implementing Swal.fire, Swal.close, Swal.showLoading
// This shim uses native modals for simplicity (not full-featured), but satisfies
// the project calls: Swal.fire({...}).then(result => ...), Swal.showLoading(), Swal.close().
(function(global){
    const Swal = {
        fire: function(options){
            // options: { title, text/message, icon, showCancelButton, confirmButtonText, cancelButtonText }
            return new Promise(resolve => {
                try {
                    const title = options && (options.title || '');
                    const text = options && (options.text || options.message || '') ;
                    if (options && options.showCancelButton) {
                        const ok = window.confirm((title ? title + '\n\n' : '') + text);
                        resolve({ isConfirmed: ok });
                    } else {
                        window.alert((title ? title + '\n\n' : '') + text);
                        resolve({ isConfirmed: true });
                    }
                } catch (e) {
                    // fallback
                    window.alert(options && (options.title || options.text || options.message) || '');
                    resolve({ isConfirmed: true });
                }
            });
        },
        close: function(){ /* no-op with native dialogs */ },
        showLoading: function(){ /* no-op */ }
    };
    global.Swal = Swal;
})(window);
